import os
from humanize import naturalsize

def get_all_files(path):
    for root, _, filenames in os.walk(path):
        for filename in filenames:
            yield os.path.join(root, filename)

def get_dir_sizes(files):
    for file in files:
        yield os.path.getsize(file)

def large_files(path):
    files = get_all_files(path)
    sizes = set(get_dir_sizes(files))
    largest = (
        sorted(sizes, reverse=True)[:20]
        if len(sizes) > 20
        else sorted(sizes, reverse=True)
    )
    return [{'file': file, 'size': naturalsize(size)} for file, size in largest]
